import{_ as e,o as s,c as i,ag as t}from"./chunks/framework.BuUvxvtQ.js";const _=JSON.parse('{"title":"О проекте","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),l={name:"about.md"};function d(r,a,n,o,c,p){return s(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="о-проекте" tabindex="-1">О проекте <a class="header-anchor" href="#о-проекте" aria-label="Permalink to &quot;О проекте&quot;">​</a></h1><p>Этот сайт создан как учебный ресурс по теме личной кибербезопасности в социальных сетях. Он помогает понять, какие настройки действительно влияют на безопасность аккаунта и какие повседневные действия снижают риск компрометации.</p><h2 id="задачи-проекта" tabindex="-1">Задачи проекта <a class="header-anchor" href="#задачи-проекта" aria-label="Permalink to &quot;Задачи проекта&quot;">​</a></h2><div class="card-grid"><div class="info-card"><h3>Повысить осведомленность</h3><p>Показать, что защита аккаунта важна не только публичным людям, но и любому пользователю, который хранит личные данные, переписки и фотографии.</p></div><div class="info-card"><h3>Дать практические шаги</h3><p>Собрать рекомендации, которые можно выполнить без специальных технических знаний: включить 2FA, проверить сеансы, обновить пароль, настроить приватность.</p></div><div class="info-card"><h3>Сформировать привычки</h3><p>Научить регулярно пересматривать настройки безопасности, замечать тревожные признаки и не доверять подозрительным сообщениям.</p></div></div><h2 id="принципы-содержания" tabindex="-1">Принципы содержания <a class="header-anchor" href="#принципы-содержания" aria-label="Permalink to &quot;Принципы содержания&quot;">​</a></h2><ul><li>материалы написаны простым и понятным языком;</li><li>контент ориентирован на безопасное поведение, профилактику и самообучение;</li><li>рекомендации не завязаны на одну платформу, но учитывают особенности популярных сервисов;</li><li>структура сайта позволяет использовать его как конспект, памятку и демонстрационный учебный стенд.</li></ul><h2 id="что-особенно-важно" tabindex="-1">Что особенно важно <a class="header-anchor" href="#что-особенно-важно" aria-label="Permalink to &quot;Что особенно важно&quot;">​</a></h2><div class="badge-line"><span class="badge">Защита персональных данных</span><span class="badge">Безопасное общение</span><span class="badge">Проверка устройств</span><span class="badge">Распознавание фишинга</span><span class="badge">Восстановление доступа</span></div>',8)])])}const u=e(l,[["render",d]]);export{_ as __pageData,u as default};
